  class Property {
    var key: Expr?
    var value: Expr?
    constructor(key_: Expr?, value_: Expr?) {
      key := key_;
      value := value_;
    }
  }

  class Array {
    var items: seq<Expr>
    constructor() { items := []; }
    method {:verify false} Push(value: Expr)
      modifies this
